const { Document, Packer, Paragraph, TextRun, Header, Footer, Table, TableRow, TableCell,
  AlignmentType, HeadingLevel, PageNumber, BorderStyle, ShadingType, WidthType,
  PageOrientation, NumberFormat } = require("docx");
const fs = require("fs");

// ── Palette: Education / Training (Warm Sun) ──
const P = {
  primary: "2A3518", body: "384228", secondary: "6B8040",
  accent: "D4A030", surface: "F8FAF4",
  cover: { titleColor: "FFFFFF", subtitleColor: "B0B8C0", metaColor: "90989F", footerColor: "687078" }
};
const c = (hex) => hex.replace("#", "");

// ── Helper Functions ──
function heading(text, level = HeadingLevel.HEADING_1) {
  return new Paragraph({
    heading: level,
    spacing: { before: level === HeadingLevel.HEADING_1 ? 360 : 240, after: 120 },
    children: [new TextRun({ text, bold: true, color: c(P.primary), font: { ascii: "Calibri", eastAsia: "SimHei" } })]
  });
}

function body(text) {
  return new Paragraph({
    alignment: AlignmentType.JUSTIFIED,
    spacing: { line: 312, after: 80 },
    children: [new TextRun({ text, size: 24, color: c(P.body), font: { ascii: "Calibri", eastAsia: "Microsoft YaHei" } })],
  });
}

function bodyBold(text) {
  return new Paragraph({
    alignment: AlignmentType.JUSTIFIED,
    spacing: { line: 312, after: 80 },
    children: [new TextRun({ text, size: 24, bold: true, color: c(P.primary), font: { ascii: "Calibri", eastAsia: "SimHei" } })],
  });
}

function bullet(text) {
  return new Paragraph({
    alignment: AlignmentType.LEFT,
    spacing: { line: 312, after: 60 },
    indent: { left: 480 },
    children: [
      new TextRun({ text: "\u2022 ", size: 24, color: c(P.accent), font: { ascii: "Calibri" } }),
      new TextRun({ text, size: 24, color: c(P.body), font: { ascii: "Calibri", eastAsia: "Microsoft YaHei" } }),
    ],
  });
}

function numberedItem(num, text) {
  return new Paragraph({
    alignment: AlignmentType.LEFT,
    spacing: { line: 312, after: 60 },
    indent: { left: 480 },
    children: [
      new TextRun({ text: `${num}. `, size: 24, bold: true, color: c(P.accent), font: { ascii: "Calibri" } }),
      new TextRun({ text, size: 24, color: c(P.body), font: { ascii: "Calibri", eastAsia: "Microsoft YaHei" } }),
    ],
  });
}

function spacer(h = 200) {
  return new Paragraph({ spacing: { before: h } });
}

// ── Table builder ──
const cellBorders = {
  top: { style: BorderStyle.SINGLE, size: 1, color: "D0D0D0" },
  bottom: { style: BorderStyle.SINGLE, size: 1, color: "D0D0D0" },
  left: { style: BorderStyle.SINGLE, size: 1, color: "D0D0D0" },
  right: { style: BorderStyle.SINGLE, size: 1, color: "D0D0D0" },
};

function makeTable(headers, rows) {
  const headerRow = new TableRow({
    tableHeader: true,
    children: headers.map(h => new TableCell({
      children: [new Paragraph({ alignment: AlignmentType.CENTER, children: [new TextRun({ text: h, bold: true, size: 22, color: "FFFFFF", font: { ascii: "Calibri", eastAsia: "SimHei" } })] })],
      shading: { type: ShadingType.CLEAR, fill: c(P.accent) },
      margins: { top: 60, bottom: 60, left: 120, right: 120 },
      borders: cellBorders,
    })),
  });

  const dataRows = rows.map((row, ri) => new TableRow({
    children: row.map(cell => new TableCell({
      children: [new Paragraph({ alignment: AlignmentType.CENTER, spacing: { line: 280 }, children: [new TextRun({ text: cell, size: 22, color: c(P.body), font: { ascii: "Calibri", eastAsia: "Microsoft YaHei" } })] })],
      shading: ri % 2 === 0 ? { type: ShadingType.CLEAR, fill: c(P.surface) } : { type: ShadingType.CLEAR, fill: "FFFFFF" },
      margins: { top: 60, bottom: 60, left: 120, right: 120 },
      borders: cellBorders,
    })),
  }));

  return new Table({
    width: { size: 100, type: WidthType.PERCENTAGE },
    rows: [headerRow, ...dataRows],
  });
}

