  content.push(body("\u0645\u0639\u0631\u0641\u0629 \u0627\u0644\u0641\u0626\u0629 \u0627\u0644\u0645\u0633\u062a\u0647\u062f\u0641\u0629 \u0645\u0647\u0645\u0629 \u062c\u062f\u0627\u064b \u0644\u0643\u062a\u0627\u0628\u0629 \u0627\u0644\u0633\u0643\u0631\u064a\u0628\u062a\u0627\u062a. \u0627\u0644\u0645\u0639\u0644\u0645 \u0627\u0644\u0633\u0648\u0631\u064a \u0631\u0627\u062a\u0628\u0647 \u0628\u064a\u0646 $70-120 \u0634\u0647\u0631\u064a\u0627\u064b\u060c \u064a\u0639\u0646\u064a $12 \u0639\u0644\u064a\u0647 \u0645\u0628\u0644\u063a \u0643\u0628\u064a\u0631 \u0646\u0633\u0628\u064a\u0627\u064b (10-17% \u0645\u0646 \u0627\u0644\u0631\u0627\u062a\u0628). \u0644\u0647\u064a\u0643 \u0627\u0644\u0633\u0639\u0631 \u0645\u0628\u0646\u064a \u0639\u0644\u0649 \u0627\u0644\u062a\u062d\u0644\u064a\u0644: $12 = \u0623\u0642\u0644 \u0645\u0646 400 \u0644\u064a\u0631\u0629 \u0628\u0627\u0644\u064a\u0648\u0645 \u0639\u0644\u0649 \u0645\u062f\u0627\u0631 \u0633\u0646\u0629\u060c \u0648\u0647\u0627\u062f \u0623\u0642\u0644 \u0645\u0646 \u0633\u0639\u0631 \u0643\u0627\u0633\u0629 \u0634\u0627\u064a \u064a\u0648\u0645\u064a\u0627\u064b. \u0627\u0644\u0636\u0645\u0627\u0646 7 \u0623\u064a\u0627\u0645 \u0628\u064a\u062e\u0644\u064a \u0627\u0644\u0645\u0639\u0644\u0645 \u064a\u062c\u0631\u0628 \u0628\u062f\u0648\u0646 \u0645\u062e\u0627\u0637\u0631\u0629."));

